// Get the rows from the Databricks result
const rows = $json.result.data_array;

// Map the rows into a structured object
const structuredSchema = rows.map(row => {
  return {
    column: row[0],
    type: row[1],
    description: row[2] || "No description provided"
  };
});

// Create a simplified string version for the AI Prompt
const simpleText = rows.map(row => `- ${row[0]} (${row[1]})`).join('\n');

return [{
  json: {
    table_name: "franchises", // You can pass this dynamically if needed
    columns_count: structuredSchema.length,
    schema_details: structuredSchema,
    ai_friendly_schema: simpleText
  }
}];

